import{_ as t,I as r,c as i,o as n,j as a,J as s,ah as d,a as l}from"./chunks/framework.kC6eLDwR.js";const _=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md"}'),p={name:"guide/faq.md"};function c(h,e,g,u,f,m){const o=r("CopyOrDownloadAsMarkdownButtons");return n(),i("div",null,[e[0]||(e[0]=a("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /j20/guide/faq.md for this page in Markdown format",-1)),e[1]||(e[1]=a("h1",{id:"常见问题",tabindex:"-1"},[l("常见问题 "),a("a",{class:"header-anchor",href:"#常见问题","aria-label":"Permalink to “常见问题”"},"​")],-1)),s(o),e[2]||(e[2]=d('<h2 id="响应链传递" tabindex="-1">响应链传递 <a class="header-anchor" href="#响应链传递" aria-label="Permalink to “响应链传递”">​</a></h2><p>只有 <code>$</code> 前缀的变量才会被编译成信号，所以，信号传递过程中不能中断，必须传递给 <code>$</code> 开头的变量，才能保持响应性，解构的时候需要尤其注意，解构的变量名要设置别名为 <code>$</code> 开头的。</p><p>信号的传递路径，以自定义 hook 为例子：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>声明信号 -&gt; 派生信号 -&gt; hook(入参信号) -&gt; hook(返回值信号) -&gt; 派生信号/解构信号</span></span></code></pre></div><p>这里每一步都会进行信号编译，响应才不会中断，这就是信号的响应链传递。</p><h2 id="为什么要加-前缀" tabindex="-1">为什么要加 <code>$</code> 前缀? <a class="header-anchor" href="#为什么要加-前缀" aria-label="Permalink to “为什么要加 $ 前缀?”">​</a></h2><p>第一：为了编译时将符号 <code>$</code> 前缀的变量编译成和信号相关的代码所做的标记，这个标记是明确的没有歧义的（避免极少数三方库的冲突，请自行别名处理），编译插件已经开源，具体原理可以看 <a href="https://github.com/anuoua/signal-compiler" target="_blank" rel="noreferrer">signal-compiler</a></p><p>第二：为了避免和普通变量（非 Signal）混淆。在大型应用中<strong>变量的数量庞大</strong>，开发人员无法区分信号变量和普通变量，导致 debug 困难。</p>',8))])}const b=t(p,[["render",c]]);export{_ as __pageData,b as default};
